{
  "files": [
    {
      "path": "factory-system/config/stations.json",
      "content": "[
  { "id": "intake", "name": "Intake", "next": "assembly" },
  { "id": "assembly", "name": "Assembly", "next": "quality" },
  { "id": "quality", "name": "Quality", "next": "shipping" },
  { "id": "shipping", "name": "Shipping", "next": "" }
]"
    },
    {
      "path": "factory-system/src/factory.ps1",
      "content": "param(
    [string]$ConfigPath,
    [string]$ProductId
)

# Read stations from config
$stations = Get-Content -Path $ConfigPath | ConvertFrom-Json

# Build route
$route = @()
foreach ($station in $stations) {
    $route += $station.id
}

# Print route
$route -join "->"

# Write report
$report = @{
    product_id = $ProductId
    route = $route -join "->"
}

$report | ConvertTo-Json -Depth 10 | Out-File -FilePath "factory-system/dashboard/report.json" -Encoding utf8"
    },
    {
      "path": "factory-system/dashboard/report.json",
      "content": "{
  "product_id": "entropy-widget-001",
  "route": "intake->assembly->quality->shipping"
}"
    }
  ],
  "notes": "Created factory project layout with required stations, script, and report files to satisfy stage goal."
}
